import type { LeaderboardEntry } from "@/lib/leaderboard";

interface LeaderboardListProps {
  entries: LeaderboardEntry[];
}

export function LeaderboardList({ entries }: LeaderboardListProps) {
  return (
    <div className="bg-white rounded-lg shadow-sm border border-[#d8d9db] overflow-hidden">
      <div className="bg-[#5b6880] px-6 py-4">
        <h2 className="text-white font-semibold text-lg">Full Rankings</h2>
      </div>
      <ul className="divide-y divide-[#d8d9db]" aria-label="Leaderboard by kudos received">
        {entries.map((entry, index) => (
          <li key={entry.id}>
            <article
              className="flex items-center justify-between gap-4 p-4 hover:bg-[#f5f6f8] transition-colors"
              aria-label={`${entry.displayName ?? entry.name}, ${entry.kudosReceived} kudos`}
            >
              <div className="flex items-center gap-4">
                <span
                  className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-[#d4d9e4] text-sm font-semibold text-[#212631]"
                  aria-hidden="true"
                >
                  {index + 1}
                </span>
                <span className="font-medium text-[#212631]">
                  {entry.displayName ?? entry.name}
                </span>
              </div>
              <span className="text-sm text-[#3d4657]">
                {entry.kudosReceived} {entry.kudosReceived === 1 ? "kudo" : "kudos"}
              </span>
            </article>
            </li>
          ))}
      </ul>
    </div>
  );
}
